#include<bits/stdc++.h>
using namespace std;
int main(){
    int a,b,i;
    long long ans=1;
    cin>>a>>b;
    a%=7;
    for(i=0;i<b;i++){
        ans*=a;
        ans%=7; //这里可以用同余定理
}
    if(ans==0){
        cout<<"Sunday";
    }else if(ans==1){
        cout<<"Monday";
    }else if(ans==2){
        cout<<"Tuesday";
    }else if(ans==3){
        cout<<"Wednesday";
    }else if(ans==4){
        cout<<"Thursday";
    }else if(ans==5){
        cout<<"Friday";
    }else if(ans==6){
        cout<<"Saturday";
    }
    return 0;
}
